static int CurrentIndex (SpinnerView spinner)
{
    FieldInfo field = typeof (SpinnerView).GetField ("_currentIdx", BindingFlags.Instance | BindingFlags.NonPublic)
                      ?? throw new InvalidOperationException ("_currentIdx field not found.");
    return (int)field.GetValue (spinner)!;
}

static bool RunScenario (string name, bool initialAutoSpin, bool enableDuringRun, bool expectedAdvanced)
{
    using IApplication app = Application.Create ();
    app.Init (DriverRegistry.Names.ANSI);

    using Window main = new () { Title = name };
    SpinnerView spinner = new ()
    {
        X = Pos.Center (),
        Y = Pos.Center (),
        SpinDelay = 10,
        AutoSpin = initialAutoSpin
    };

    main.Add (spinner);
    int before = CurrentIndex (spinner);

    if (enableDuringRun)
    {
        app.AddTimeout (TimeSpan.FromMilliseconds (20), () =>
        {
            spinner.AutoSpin = true;
            return false;
        });
    }

    app.AddTimeout (TimeSpan.FromMilliseconds (170), () =>
    {
        app.RequestStop (main);
        return false;
    });

    app.Run (main);
    int after = CurrentIndex (spinner);
    bool advanced = after != before;
    bool passed = advanced == expectedAdvanced;

    Console.WriteLine ($"{name}: AutoSpin={spinner.AutoSpin}; Before={before}; After={after}; Advanced={advanced}; ExpectedAdvanced={expectedAdvanced}; Passed={passed}");

    return passed;
}

